# -- Helpers ------------------------------------------------------------------
def _noop():
    """Module-level no-op used to replace save_data_plot on Plotter instances.
    Must be at module scope so pickle can serialise the object."""
    pass

def style_widget(w, **kw):
    """Apply common dark-theme defaults then override with kw."""
    defaults = dict(bg=PANEL, fg=TEXT, font=FONT_B,
                    relief="flat", bd=0, highlightthickness=0)
    defaults.update(kw)
    try:
        w.configure(**defaults)
    except Exception:
        pass


def make_entry(parent, textvariable=None, width=20, **kw):
    e = tk.Entry(parent, textvariable=textvariable, width=width,
                 bg=CARD, fg=TEXT, insertbackground=TEXT,
                 relief="flat", font=FONT_B,
                 highlightthickness=1, highlightbackground=BORDER,
                 highlightcolor=ACCENT, **kw)
    return e


def make_button(parent, text, command, accent=False, small=False, **kw):
    c = ACCENT if accent else CARD
    f = FONT_S if small else FONT_B
    b = tk.Button(parent, text=text, command=command,
                  bg=c, fg=TEXT, activebackground=ACCENT2,
                  activeforeground=TEXT, relief="flat", font=f,
                  cursor="hand2", padx=12, pady=6, **kw)
    b.bind("<Enter>", lambda e: b.configure(bg=ACCENT2 if accent else BORDER))
    b.bind("<Leave>", lambda e: b.configure(bg=c))
    return b


def make_label(parent, text, big=False, dim=False, **kw):
    f = FONT_L if big else FONT_B
    c = TEXT_DIM if dim else TEXT
    return tk.Label(parent, text=text, bg=PANEL, fg=c, font=f, **kw)


def section_label(parent, text):
    frm = tk.Frame(parent, bg=PANEL)
    tk.Label(frm, text=text, bg=PANEL, fg=ACCENT, font=FONT_H).pack(side="left")
    tk.Frame(frm, bg=BORDER, height=1).pack(side="left", fill="x", expand=True, padx=(8, 0))
    return frm


def scrollable_frame(parent):
    """Returns (outer_frame, inner_frame) - pack/grid outer, add widgets to inner."""
    outer = tk.Frame(parent, bg=PANEL)
    canvas = tk.Canvas(outer, bg=PANEL, highlightthickness=0)
    sb = tk.Scrollbar(outer, orient="vertical", command=canvas.yview,
                      bg=PANEL, troughcolor=BG, activebackground=ACCENT)
    inner = tk.Frame(canvas, bg=PANEL)
    inner.bind("<Configure>",
               lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
    canvas.create_window((0, 0), window=inner, anchor="nw")
    canvas.configure(yscrollcommand=sb.set)
    canvas.pack(side="left", fill="both", expand=True)
    sb.pack(side="right", fill="y")

    def _on_mousewheel(event):
        canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")
    canvas.bind_all("<MouseWheel>", _on_mousewheel)
    return outer, inner


# -- mat helper (mirrors PlotterClass) ----------------------------------------
def mat_struct_to_dataframe(path: str, file: str) -> pd.DataFrame:
    mat = loadmat(os.path.join(path, file), squeeze_me=True)
    columns = {}
    for key, value in mat.items():
        if key.startswith("__"):
            continue
        if not isinstance(value, np.ndarray):
            continue
        if not np.issubdtype(value.dtype, np.floating):
            continue
        columns[key] = value.flatten()
    if not columns:
        raise ValueError("No double vector fields found in the .mat file.")
    lengths = {n: a.size for n, a in columns.items()}
    if len(set(lengths.values())) > 1:
        raise ValueError(f"Mismatched field lengths: {lengths}")
    return pd.DataFrame(columns)


def load_file(path: str, file: str) -> pd.DataFrame:
    if file.endswith('.xlsx'):
        return pd.read_excel(os.path.join(path, file))
    elif file.endswith('.csv'):
        return pd.read_csv(os.path.join(path, file))
    elif file.endswith('.mat'):
        return mat_struct_to_dataframe(path, file)
    raise ValueError(f"Unsupported file type: {file}")


