# WINDOW 1 - Mode Selection
# ============================================================================
class Window1_ModeSelect(tk.Tk):
    MODES = [
        ("plot_pickle",      "[PKL]  Plot from Pickle",   "Replot a previously saved plot configuration"),
        ("plot_single_axis", "[Y1]   Single Axis Plot",   "Plot one or more signals on a shared Y-axis"),
        ("plot_twin_axes",   "[Y2]   Twin Axes Plot",     "Plot signals on two independent Y-axes"),
        ("plot_bode",        "[FFT]  Bode Plot",          "Frequency-domain magnitude & phase from chirp data"),
    ]

    def __init__(self):
        super().__init__()
        self.title("Plotter")
        self.configure(bg=BG)
        self.resizable(False, False)
        self._mode = tk.StringVar(value="plot_single_axis")
        self._build()
        self.eval('tk::PlaceWindow . center')

    def _build(self):
        # Header
        hdr = tk.Frame(self, bg=ACCENT, pady=16)
        hdr.pack(fill="x")
        tk.Label(hdr, text="PYTHON PLOTTER", bg=ACCENT, fg=BG,
                 font=("Courier New", 22, "bold")).pack()
        tk.Label(hdr, text="quickly visualize data in python",
                 bg=ACCENT, fg=BG, font=FONT_S).pack()

        body = tk.Frame(self, bg=BG, padx=32, pady=24)
        body.pack(fill="both")

        tk.Label(body, text="SELECT PLOT MODE", bg=BG, fg=TEXT_DIM,
                 font=FONT_H).pack(anchor="w", pady=(0, 12))

        for val, title, desc in self.MODES:
            card = tk.Frame(body, bg=PANEL, pady=10, padx=14,
                            highlightthickness=1, highlightbackground=BORDER,
                            cursor="hand2")
            card.pack(fill="x", pady=5)

            rb = tk.Radiobutton(card, variable=self._mode, value=val,
                                bg=PANEL, activebackground=PANEL,
                                selectcolor=BG, fg=ACCENT,
                                highlightthickness=0)
            rb.pack(side="left")

            tk.Label(card, text=title, bg=PANEL, fg=TEXT,
                     font=FONT_H).pack(side="left", padx=4)
            tk.Label(card, text=desc, bg=PANEL, fg=TEXT_DIM,
                     font=FONT_S).pack(side="left", padx=8)

            card.bind("<Button-1>", lambda e, v=val: self._mode.set(v))
            for child in card.winfo_children():
                child.bind("<Button-1>", lambda e, v=val: self._mode.set(v))

        make_button(body, "CONTINUE  >>", self._continue,
                    accent=True).pack(pady=(20, 0), fill="x")

    def _continue(self):
        mode = self._mode.get()
        self.destroy()
        Window2_FileSelect(mode).mainloop()


# ============================================================================
# WINDOW 2 - Folder + File Selection
# ============================================================================
class Window2_FileSelect(tk.Tk):
    def __init__(self, mode: str):
        super().__init__()
        self.mode = mode
        self.title("Plotter - Select Data Files")
        self.configure(bg=BG)
        self.geometry("640x560")
        self._folder = tk.StringVar()
        self._file_vars = {}   # filename -> BooleanVar
        self._dataframes = {}
        self._build()
        self.eval('tk::PlaceWindow . center')

    def _build(self):
        # Pickle mode needs no file selection -- jump straight to config
        if self.mode == "plot_pickle":
            folder = filedialog.askdirectory(title="Select folder containing 'Pickles' subfolder")
            self.destroy()
            Window3_Config("plot_pickle", folder or "", {}, {}).mainloop()
            return

        hdr = tk.Frame(self, bg=PANEL, pady=12, padx=20)
        hdr.pack(fill="x")
        tk.Label(hdr, text=f"MODE: {self.mode.replace('_',' ').upper()}",
                 bg=PANEL, fg=ACCENT, font=FONT_H).pack(anchor="w")
        tk.Label(hdr, text="Step 1 of 2  -  Choose data folder & files",
                 bg=PANEL, fg=TEXT_DIM, font=FONT_S).pack(anchor="w")

        body = tk.Frame(self, bg=BG, padx=28, pady=20)
        body.pack(fill="both", expand=True)

        # Folder row
        tk.Label(body, text="DATA FOLDER", bg=BG, fg=TEXT_DIM,
                 font=FONT_H).pack(anchor="w")
        row = tk.Frame(body, bg=BG)
        row.pack(fill="x", pady=(4, 16))
        e = make_entry(row, textvariable=self._folder, width=46)
        e.pack(side="left", padx=(0, 8))
        make_button(row, "Browse", self._browse).pack(side="left")

        # File list area
        tk.Label(body, text="SELECT FILES TO PLOT", bg=BG, fg=TEXT_DIM,
                 font=FONT_H).pack(anchor="w")
        tk.Label(body, text="(check all files you want to include)",
                 bg=BG, fg=TEXT_DIM, font=FONT_S).pack(anchor="w", pady=(0, 6))

        list_outer, self._list_inner = scrollable_frame(body)
        list_outer.pack(fill="both", expand=True)

        self._empty_lbl = tk.Label(self._list_inner,
                                   text="??? Browse to a folder to list files",
                                   bg=PANEL, fg=TEXT_DIM, font=FONT_S, pady=16)
        self._empty_lbl.pack(fill="x")

        make_button(body, "CONTINUE  >>", self._continue,
                    accent=True).pack(pady=(16, 0), fill="x")

    def _browse(self):
        folder = filedialog.askdirectory(title="Select data folder")
        if not folder:
            return
        self._folder.set(folder)
        self._populate_files(folder)

    def _populate_files(self, folder):
        for w in self._list_inner.winfo_children():
            w.destroy()
        self._file_vars.clear()

        files = [f for f in os.listdir(folder)
                 if f.endswith(('.xlsx', '.csv', '.mat'))]

        if not files:
            tk.Label(self._list_inner, text="No .xlsx / .csv / .mat files found.",
                     bg=PANEL, fg=ACCENT2, font=FONT_S, pady=12).pack(fill="x")
            return

        for f in sorted(files):
            var = tk.BooleanVar(value=False)
            self._file_vars[f] = var
            row = tk.Frame(self._list_inner, bg=PANEL, pady=4, padx=10)
            row.pack(fill="x")
            cb = tk.Checkbutton(row, variable=var, bg=PANEL,
                                activebackground=PANEL, selectcolor=BG,
                                fg=ACCENT, highlightthickness=0)
            cb.pack(side="left")
            tk.Label(row, text=f, bg=PANEL, fg=TEXT, font=FONT_B).pack(side="left")

    def _continue(self):
        folder = self._folder.get().strip()
        if not folder or not os.path.isdir(folder):
            messagebox.showerror("Error", "Please select a valid folder.")
            return

        selected = [f for f, v in self._file_vars.items() if v.get()]

        if not selected:
            messagebox.showerror("Error", "Please select at least one file.")
            return

        # Load dataframes
        dfs = {}
        for f in selected:
            try:
                dfs[f] = load_file(folder, f)
            except Exception as ex:
                messagebox.showerror("Load Error", f"Could not load {f}:\n{ex}")
                return

        self.destroy()
        Window3_Config(self.mode, folder, selected, dfs).mainloop()


