# WINDOW 3 - Column Selection + Plot Config
# ============================================================================
class Window3_Config(tk.Tk):
    def __init__(self, mode: str, folder: str,
                 selected_files: list, dataframes: dict):
        super().__init__()
        self.mode = mode
        self.folder = folder
        self.selected_files = selected_files
        self.dataframes = dataframes

        self.title("Plotter - Configure Plot")
        self.configure(bg=BG)
        self.geometry("820x780")
        self.eval('tk::PlaceWindow . center')

        # -- shared state --
        self._plotstyle   = tk.StringVar(value="seaborn-talk")
        self._title       = tk.StringVar(value="")
        self._xlabel      = tk.StringVar(value="")
        self._ylabel1     = tk.StringVar(value="")
        self._ylabel2     = tk.StringVar(value="")
        self._xlim_lo     = tk.StringVar(value="")
        self._xlim_hi     = tk.StringVar(value="")
        self._ylim1_lo    = tk.StringVar(value="")
        self._ylim1_hi    = tk.StringVar(value="")
        self._ylim2_lo    = tk.StringVar(value="")
        self._ylim2_hi    = tk.StringVar(value="")
        self._legend      = tk.BooleanVar(value=True)
        self._verbose     = tk.BooleanVar(value=False)
        self._figw        = tk.StringVar(value="10")
        self._figh        = tk.StringVar(value="6")
        self._title_fs    = tk.StringVar(value="")
        self._label_fs    = tk.StringVar(value="")
        self._tick_fs     = tk.StringVar(value="")
        self._legend_fs   = tk.StringVar(value="")

        # save options
        self._save_pickle  = tk.BooleanVar(value=False)
        self._pickle_name  = tk.StringVar(value="")
        self._save_png     = tk.BooleanVar(value=False)
        self._png_name     = tk.StringVar(value="")

        # bode-specific
        self._start_freq  = tk.StringVar(value="50")
        self._end_freq    = tk.StringVar(value="200")
        self._sample_rate = tk.StringVar(value="10000")

        # column selection data (built dynamically)
        # x_selections[file] = column StringVar
        # y_selections[file] = list of {col: StringVar, label: StringVar, axis: IntVar}
        # For bode: input_selections[file][y_col_var] = StringVar for input col
        self._x_file      = tk.StringVar()
        self._x_col       = tk.StringVar()
        self._y_rows      = {}   # file -> list of row-dicts
        self._bode_inputs = {}   # file -> list of input StringVars (parallel to _y_rows)

        self._build()

    # -- Top-level layout ----------------------------------------------------
    def _build(self):
        # Header strip
        hdr = tk.Frame(self, bg=PANEL, pady=12, padx=20)
        hdr.pack(fill="x")
        tk.Label(hdr, text=f"MODE: {self.mode.replace('_',' ').upper()}",
                 bg=PANEL, fg=ACCENT, font=FONT_H).pack(anchor="w")
        tk.Label(hdr, text="Step 2 of 2  -  Configure columns & plot properties",
                 bg=PANEL, fg=TEXT_DIM, font=FONT_S).pack(anchor="w")

        # Main scrollable body
        outer, body = scrollable_frame(self)
        outer.pack(fill="both", expand=True, padx=0, pady=0)
        body.configure(padx=28, pady=16)

        if self.mode == "plot_pickle":
            self._build_pickle_section(body)
        else:
            if self.mode != "plot_bode":
                self._build_x_section(body)
            self._build_y_section(body)
            if self.mode == "plot_bode":
                self._build_bode_params(body)

        self._build_props_section(body)

        # Footer button
        foot = tk.Frame(self, bg=BG, pady=12, padx=28)
        foot.pack(fill="x", side="bottom")
        make_button(foot, ">>  GENERATE PLOT", self._run,
                    accent=True).pack(fill="x")

    # -- Pickle section -------------------------------------------------------
    def _build_pickle_section(self, body):
        section_label(body, "PICKLE FILE").pack(fill="x", pady=(0, 10))
        tk.Label(body, text="Pickle files are loaded from the 'Pickles' subfolder inside your data folder.",
                 bg=PANEL, fg=TEXT_DIM, font=FONT_S, wraplength=700,
                 justify="left").pack(anchor="w", pady=(0, 8))

        pdir = os.path.join(self.folder, "Pickles")
        if os.path.isdir(pdir):
            pickles = [f for f in os.listdir(pdir) if f.endswith('.pkl')]
        else:
            pickles = []

        # _pickle_label_vars: {file: [ {col, axis(opt), label_var}, ... ]}
        # populated by _on_pickle_select whenever the selection changes
        self._pickle_label_vars = {}

        self._pickle_var = tk.StringVar()
        if pickles:
            self._pickle_var.set(pickles[0])
            for p in pickles:
                rb = tk.Radiobutton(body, text=p, variable=self._pickle_var,
                                    value=p, bg=PANEL, fg=TEXT,
                                    selectcolor=BG, activebackground=PANEL,
                                    font=FONT_B, highlightthickness=0,
                                    command=self._on_pickle_select)
                rb.pack(anchor="w")

            # Container for the editable-labels panel (rebuilt on each selection)
            self._pickle_labels_frame = tk.Frame(body, bg=PANEL)
            self._pickle_labels_frame.pack(fill="x", pady=(12, 0))

            # Show labels for the initially-selected pickle straight away
            self._on_pickle_select()
        else:
            tk.Label(body, text="[!] No pickle files found in 'Pickles' subfolder.",
                     bg=PANEL, fg=ACCENT2, font=FONT_B).pack(anchor="w")

    def _on_pickle_select(self):
        """Load the selected pickle and rebuild the editable label rows."""
        # Clear previous contents
        for w in self._pickle_labels_frame.winfo_children():
            w.destroy()
        self._pickle_label_vars = {}

        pkl_name = self._pickle_var.get()
        if not pkl_name:
            return

        pkl_path = os.path.join(self.folder, "Pickles", pkl_name)
        try:
            with open(pkl_path, "rb") as f:
                obj = pickle.load(f)
        except Exception as ex:
            tk.Label(self._pickle_labels_frame,
                     text=f"[!] Could not load pickle: {ex}",
                     bg=PANEL, fg=ACCENT2, font=FONT_S).pack(anchor="w")
            return

        columns = getattr(obj, "columns", None)
        plot_type = getattr(obj, "plot_type", "unknown")

        if not columns:
            tk.Label(self._pickle_labels_frame,
                     text="(No column data found in this pickle.)",
                     bg=PANEL, fg=TEXT_DIM, font=FONT_S).pack(anchor="w")
            return

        section_label(self._pickle_labels_frame,
                      "COLUMN LABELS  (editable)").pack(fill="x", pady=(0, 8))

        for fname, col_tuples in columns.items():
            # File header
            tk.Label(self._pickle_labels_frame, text=fname,
                     bg=PANEL, fg=ACCENT, font=FONT_H).pack(anchor="w", pady=(4, 2))

            file_rows = []
            for entry in col_tuples:
                # Unpack regardless of tuple length (single/bode vs twin)
                if plot_type == "twin_axes":
                    col, axis, label = entry
                else:
                    col, label = entry
                    axis = None

                row = tk.Frame(self._pickle_labels_frame, bg=PANEL)
                row.pack(fill="x", pady=2)

                # Column name (read-only display)
                col_display = f"{col}"
                if axis is not None:
                    col_display += f"  [axis {axis}]"
                tk.Label(row, text=col_display, bg=PANEL, fg=TEXT,
                         font=FONT_B, width=28, anchor="w").pack(side="left")

                tk.Label(row, text="Label:", bg=PANEL, fg=TEXT_DIM,
                         font=FONT_S).pack(side="left", padx=(8, 4))

                label_var = tk.StringVar(value=label)
                make_entry(row, textvariable=label_var, width=22).pack(side="left")

                file_rows.append({"col": col, "axis": axis, "label_var": label_var})

            self._pickle_label_vars[fname] = file_rows

    # -- X-axis section -------------------------------------------------------
    def _build_x_section(self, body):
        section_label(body, "X-AXIS").pack(fill="x", pady=(0, 10))

        row = tk.Frame(body, bg=PANEL)
        row.pack(fill="x", pady=(0, 4))
        tk.Label(row, text="Source file:", bg=PANEL, fg=TEXT_DIM,
                 font=FONT_S, width=14, anchor="w").pack(side="left")

        file_opts = self.selected_files if self.selected_files else ["(none)"]
        self._x_file.set(file_opts[0])
        om_file = tk.OptionMenu(row, self._x_file, *file_opts,
                                command=self._on_x_file_change)
        om_file.configure(bg=CARD, fg=TEXT, font=FONT_B,
                          activebackground=BORDER, highlightthickness=0, relief="flat")
        om_file["menu"].configure(bg=CARD, fg=TEXT, font=FONT_B)
        om_file.pack(side="left")

        row2 = tk.Frame(body, bg=PANEL)
        row2.pack(fill="x", pady=(0, 16))
        tk.Label(row2, text="Column:", bg=PANEL, fg=TEXT_DIM,
                 font=FONT_S, width=14, anchor="w").pack(side="left")
        self._x_col_menu_frame = tk.Frame(row2, bg=PANEL)
        self._x_col_menu_frame.pack(side="left")
        self._refresh_x_col_menu()

    def _on_x_file_change(self, val):
        self._refresh_x_col_menu()

    def _refresh_x_col_menu(self):
        for w in self._x_col_menu_frame.winfo_children():
            w.destroy()
        fname = self._x_file.get()
        if fname in self.dataframes:
            cols = list(self.dataframes[fname].columns)
            self._x_col.set(cols[0])
            om = tk.OptionMenu(self._x_col_menu_frame, self._x_col, *cols)
            om.configure(bg=CARD, fg=TEXT, font=FONT_B,
                         activebackground=BORDER, highlightthickness=0, relief="flat")
            om["menu"].configure(bg=CARD, fg=TEXT, font=FONT_B)
            om.pack()

    # -- Y-axis / signal section ----------------------------------------------
    def _build_y_section(self, body):
        is_bode = self.mode == "plot_bode"
        lbl = "INPUT / OUTPUT SIGNALS" if is_bode else "Y-AXIS SIGNALS"
        section_label(body, lbl).pack(fill="x", pady=(8, 10))

        for fname in self.selected_files:
            df = self.dataframes[fname]
            cols = list(df.columns)
            self._y_rows[fname] = []
            if is_bode:
                self._bode_inputs[fname] = []

            # Per-file card
            card = tk.Frame(body, bg=CARD, padx=12, pady=10,
                            highlightthickness=1, highlightbackground=BORDER)
            card.pack(fill="x", pady=6)

            tk.Label(card, text=fname, bg=CARD, fg=ACCENT,
                     font=FONT_H).pack(anchor="w", pady=(0, 6))

            rows_frame = tk.Frame(card, bg=CARD)
            rows_frame.pack(fill="x")

            # store ref so we can add rows
            card._rows_frame = rows_frame
            card._fname      = fname
            card._cols       = cols
            card._is_bode    = is_bode

            self._add_y_row(card)

            make_button(card, "+  Add Signal", lambda c=card: self._add_y_row(c),
                        small=True).pack(anchor="w", pady=(6, 0))

    def _add_y_row(self, card):
        fname  = card._fname
        cols   = card._cols
        is_bode = card._is_bode
        rf     = card._rows_frame

        row_bg = CARD
        row = tk.Frame(rf, bg=row_bg, pady=4)
        row.pack(fill="x")

        col_var   = tk.StringVar(value=cols[0])
        label_var = tk.StringVar(value="")

        if is_bode:
            # Output col
            tk.Label(row, text="Output col:", bg=row_bg, fg=TEXT_DIM,
                     font=FONT_S, width=10, anchor="w").grid(row=0, column=0, sticky="w")
            om = tk.OptionMenu(row, col_var, *cols)
