    # -- Bode params ----------------------------------------------------------
    def _build_bode_params(self, body):
        section_label(body, "BODE PARAMETERS").pack(fill="x", pady=(12, 8))
        grid = tk.Frame(body, bg=PANEL)
        grid.pack(anchor="w")
        for col_i, (lbl, var) in enumerate([
                ("Start Freq (Hz)", self._start_freq),
                ("End Freq (Hz)",   self._end_freq),
                ("Sampling Rate (Hz)", self._sample_rate)]):
            tk.Label(grid, text=lbl, bg=PANEL, fg=TEXT_DIM,
                     font=FONT_S).grid(row=0, column=col_i*2, sticky="w", padx=(0, 4), pady=2)
            make_entry(grid, textvariable=var, width=10).grid(row=0, column=col_i*2+1, padx=(0, 16))

