        tk.Label(lim_row, text="  (leave blank for auto)", bg=PANEL, fg=TEXT_DIM, font=FONT_S).pack(side="left")

        tk.Label(outer, text="Y1 Limits", bg=PANEL, fg=TEXT_DIM,
                 font=FONT_S, width=14, anchor="w").grid(row=11, column=0, sticky="w", pady=3)
        lim_row2 = tk.Frame(outer, bg=PANEL)
        lim_row2.grid(row=11, column=1, sticky="w")
        make_entry(lim_row2, textvariable=self._ylim1_lo, width=8).pack(side="left")
        tk.Label(lim_row2, text=" to ", bg=PANEL, fg=TEXT_DIM, font=FONT_S).pack(side="left")
        make_entry(lim_row2, textvariable=self._ylim1_hi, width=8).pack(side="left")

        if self.mode in ("plot_twin_axes", "plot_bode"):
            tk.Label(outer, text="Y2 Limits", bg=PANEL, fg=TEXT_DIM,
                     font=FONT_S, width=14, anchor="w").grid(row=12, column=0, sticky="w", pady=3)
            lim_row3 = tk.Frame(outer, bg=PANEL)
            lim_row3.grid(row=12, column=1, sticky="w")
            make_entry(lim_row3, textvariable=self._ylim2_lo, width=8).pack(side="left")
            tk.Label(lim_row3, text=" to ", bg=PANEL, fg=TEXT_DIM, font=FONT_S).pack(side="left")
            make_entry(lim_row3, textvariable=self._ylim2_hi, width=8).pack(side="left")

        # Figure size + font sizes
        section_label(body, "FIGURE & FONT SIZES (leave blank for defaults)").pack(fill="x", pady=(16, 8))
        sz = tk.Frame(body, bg=PANEL)
        sz.pack(anchor="w")

        for ci, (lbl, var) in enumerate([
                ("Fig Width",  self._figw),
                ("Fig Height", self._figh),
                ("Title FS",   self._title_fs),
                ("Label FS",   self._label_fs),
                ("Tick FS",    self._tick_fs),
                ("Legend FS",  self._legend_fs)]):
            tk.Label(sz, text=lbl, bg=PANEL, fg=TEXT_DIM,
                     font=FONT_S).grid(row=0, column=ci*2, sticky="w", padx=(0, 4))
            make_entry(sz, textvariable=var, width=6).grid(row=0, column=ci*2+1, padx=(0, 12))

        # Legend + Verbose
        tog = tk.Frame(body, bg=PANEL, pady=8)
