    # -- Toggle helpers for save entries --------------------------------------
    def _toggle_pickle_name(self):
        state = "normal" if self._save_pickle.get() else "disabled"
        self._pkl_name_entry.configure(state=state)

    def _toggle_png_name(self):
        state = "normal" if self._save_png.get() else "disabled"
        self._png_name_entry.configure(state=state)

    # -- Parse helpers --------------------------------------------------------
    def _parse_float(self, s, default=False):
        s = s.strip()
        if not s:
            return default
        try:
            return float(s)
        except ValueError:
            return default

    def _parse_limits(self, lo_var, hi_var):
        lo = self._parse_float(lo_var.get())
        hi = self._parse_float(hi_var.get())
        if lo is False or hi is False:
            return False
        return (lo, hi)

    def _parse_fontsize(self, var):
        v = self._parse_float(var.get())
        return int(v) if v is not False else False

    # -- GUI-driven save (replaces save_data_plot input() prompts) ------------
    def _gui_save(self, plotter, fig=None):
        """Save pickle and/or PNG. fig must be the fully-drawn Figure object.
        PNG is saved immediately from the figure; pickle serialises the plotter state."""

        # Pickle save -- no figure needed, order doesn't matter
        if self._save_pickle.get():
            pkl_name = self._pickle_name.get().strip()
            if not pkl_name:
                messagebox.showwarning("Pickle Save", "Enter a filename for the pickle.")
            else:
                pkl_dir = os.path.join(self.folder, "Pickles")
                os.makedirs(pkl_dir, exist_ok=True)
                pkl_path = os.path.join(pkl_dir, pkl_name + ".pkl")
                with open(pkl_path, "wb") as f:
                    pickle.dump(plotter, f)
                print(f"Settings pickled to: {pkl_path}")

        # PNG save -- must happen BEFORE plt.show() while the figure is populated
        if self._save_png.get():
            if fig is None:
                fig = plt.gcf()
            png_name = self._png_name.get().strip()
            if not png_name:
                png_name = plotter.title if plotter.title else "plot"
            png_dir = os.path.join(self.folder, "Plots")
            os.makedirs(png_dir, exist_ok=True)
            png_path = os.path.join(png_dir, png_name + ".png")
            fig.savefig(png_path, bbox_inches="tight", dpi=300)
            print(f"Plot saved to: {png_path}")

    # -- Run ------------------------------------------------------------------
    def _run(self):
        try:
            self._do_run()
        except Exception as ex:
            messagebox.showerror("Error", str(ex))
            import traceback; traceback.print_exc()

    def _do_run(self):
        # Build shared Plotter kwargs
        figw = self._parse_float(self._figw.get(), 10)
        figh = self._parse_float(self._figh.get(), 6)
        figsize = (figw, figh)

        kwargs = dict(
            foldername      = self.folder,
            plotstyle       = self._plotstyle.get(),
            verbose         = self._verbose.get(),
            title           = self._title.get().strip() or False,
            xlabel          = self._xlabel.get().strip(),
            ylabel1         = self._ylabel1.get().strip(),
            ylabel2         = self._ylabel2.get().strip(),
            xlimits         = self._parse_limits(self._xlim_lo, self._xlim_hi),
            ylimits1        = self._parse_limits(self._ylim1_lo, self._ylim1_hi),
            ylimits2        = self._parse_limits(self._ylim2_lo, self._ylim2_hi),
            legend          = self._legend.get(),
            figsize         = figsize,
            title_fontsize  = self._parse_fontsize(self._title_fs),
            label_fontsize  = self._parse_fontsize(self._label_fs),
            tick_fontsize   = self._parse_fontsize(self._tick_fs),
            legend_fontsize = self._parse_fontsize(self._legend_fs),
        )

        from PlotterClass import Plotter
        plotter = Plotter(**kwargs)

        # ── Pickle mode: load pkl, patch display settings, plot ──────────────
        if self.mode == "plot_pickle":
            pkl_name = self._pickle_var.get()
            if not pkl_name:
                messagebox.showerror("Error", "No pickle file selected.")
                return
            pkl_path = os.path.join(self.folder, "Pickles", pkl_name)
            with open(pkl_path, "rb") as f:
                plotpickle = pickle.load(f)

            # Patch all display settings from current GUI values
            plotpickle.foldername      = self.folder
            plotpickle.plotstyle       = plotter.plotstyle
            plotpickle.verbose         = plotter.verbose
            plotpickle.title           = plotter.title
            plotpickle.xlabel          = plotter.xlabel
            plotpickle.ylabel1         = plotter.ylabel1
            plotpickle.ylabel2         = plotter.ylabel2
            plotpickle.xlimits         = plotter.xlimits
            plotpickle.ylimits1        = plotter.ylimits1
            plotpickle.ylimits2        = plotter.ylimits2
            plotpickle.legend          = plotter.legend
            plotpickle.figsize         = plotter.figsize
            plotpickle.title_fontsize  = plotter.title_fontsize
            plotpickle.label_fontsize  = plotter.label_fontsize
            plotpickle.tick_fontsize   = plotter.tick_fontsize
            plotpickle.legend_fontsize = plotter.legend_fontsize

            # Apply any edited labels from the GUI back onto the loaded object
            if self._pickle_label_vars:
                new_columns = {}
                for fname, rows in self._pickle_label_vars.items():
                    tuples = []
                    for rd in rows:
                        col   = rd["col"]
                        axis  = rd["axis"]
                        label = rd["label_var"].get().strip() or col
                        if axis is not None:          # twin axes
                            tuples.append((col, axis, label))
                        else:                         # single axis / bode
                            tuples.append((col, label))
                    new_columns[fname] = tuple(tuples)
                plotpickle.columns = new_columns

            # Call plot_data directly (bypasses save_data_plot prompts)
            plotpickle.save_data_plot = _noop  # handled by _gui_save
            plotpickle.plot_data()
            fig = plt.gcf()           # capture the fully-drawn figure
            self._gui_save(plotpickle, fig=fig)   # save BEFORE show
            plt.show()
            return

        # ── Inject data into plotter (bypass select_data prompts) ────────────
        plotter.dataframes     = self.dataframes
        plotter.selected_files = self.selected_files

        if self.mode == "plot_single_axis":
            plotter.plot_type = "single_axis"

            x_file = self._x_file.get()
            x_col  = self._x_col.get()
            plotter.x_data        = x_col
            plotter.x_data_values = np.array(self.dataframes[x_file][x_col])

            columns = {}
            for fname, rows in self._y_rows.items():
                tuples = []
                for rd in rows:
                    col = rd["col"].get()
                    lbl = rd["label"].get().strip() or col
                    tuples.append((col, lbl))
                columns[fname] = tuple(tuples)
            plotter.columns = columns
            plotter.save_data_plot = _noop  # handled by _gui_save
            plotter.plot_data()
            fig = plt.gcf()                  # capture fully-drawn figure
            self._gui_save(plotter, fig=fig) # save BEFORE show
            plt.show()

        elif self.mode == "plot_twin_axes":
            plotter.plot_type = "twin_axes"

            x_file = self._x_file.get()
            x_col  = self._x_col.get()
            plotter.x_data        = x_col
            plotter.x_data_values = np.array(self.dataframes[x_file][x_col])

            columns = {}
            for fname, rows in self._y_rows.items():
                tuples = []
                for rd in rows:
                    col  = rd["col"].get()
                    lbl  = rd["label"].get().strip() or col
                    axis = rd["axis"].get()
                    tuples.append((col, axis, lbl))
                columns[fname] = tuple(tuples)
            plotter.columns = columns
            plotter.save_data_plot = _noop  # handled by _gui_save
            plotter.plot_data()
            fig = plt.gcf()                  # capture fully-drawn figure
            self._gui_save(plotter, fig=fig) # save BEFORE show
            plt.show()

        elif self.mode == "plot_bode":
            plotter.plot_type     = "bode"
            plotter.start_freq    = float(self._start_freq.get())
            plotter.end_freq      = float(self._end_freq.get())
            plotter.sampling_rate = float(self._sample_rate.get())

            pairs = []
            for fname, rows in self._y_rows.items():
                for rd in rows:
                    out_col = rd["col"].get()
                    in_col  = rd["input"].get()
                    lbl     = rd["label"].get().strip() or out_col
                    pairs.append((fname, out_col, in_col, lbl))

            if not pairs:
                messagebox.showerror("Error", "No output signals configured.")
                return

            style = plotter.plotstyle
            try:
                import scienceplots  # noqa
                if style == "science":
                    plt.style.use("science")
                elif style == "science-ieee":
                    plt.style.use(["science", "ieee"])
                else:
                    plt.style.use("seaborn-talk")
            except Exception:
                plt.style.use("seaborn-v0_8-talk")

            colors = ["tab:blue", "tab:orange", "tab:green", "tab:red",
                      "tab:purple", "tab:brown", "tab:pink", "tab:gray",
                      "tab:olive", "tab:cyan"]

            figsize = plotter.figsize or (10, 6)
            fig, (ax_mag, ax_phase) = plt.subplots(2, 1, figsize=figsize)

            for ci, (fname, out_col, in_col, lbl) in enumerate(pairs):
                df           = self.dataframes[fname]
                input_signal = np.array(df[in_col]) - np.mean(df[in_col])
                output_raw   = np.array(df[out_col])

                n    = len(input_signal)
                d    = 1.0 / plotter.sampling_rate
                freq = np.fft.rfftfreq(n, d)

                if n != len(output_raw):
                    f_i = interp1d(np.linspace(0, 1, len(output_raw)),
                                   output_raw, kind="linear",
                                   fill_value="extrapolate")
                    output_signal = f_i(np.linspace(0, 1, n)) - np.mean(output_raw)
                else:
                    output_signal = output_raw - np.mean(output_raw)

                H         = np.fft.rfft(output_signal) / np.fft.rfft(input_signal)
                magnitude = 20 * np.log10(np.abs(H))
                phase     = np.angle(H, deg=True)

                xlim = plotter.xlimits if plotter.xlimits else (plotter.start_freq, plotter.end_freq)
                ax_mag.plot(freq, magnitude, color=colors[ci % len(colors)], label=lbl)
                ax_mag.set_ylabel("Magnitude (dB)")
                ax_mag.set_xlim(xlim)
                if plotter.ylimits1:
                    ax_mag.set_ylim(plotter.ylimits1)
                ax_mag.grid(which="both", axis="both")

                ax_phase.plot(freq, phase, color=colors[ci % len(colors)], label=lbl)
                ax_phase.set_xlabel("Frequency (Hz)")
                ax_phase.set_ylabel("Phase (deg)")
                ax_phase.set_xlim(xlim)
                if plotter.ylimits2:
                    ax_phase.set_ylim(plotter.ylimits2)
                ax_phase.grid(which="both", axis="both")

            if plotter.title:
                fs = plotter.title_fontsize
                ax_mag.set_title(plotter.title, **({"fontsize": fs} if fs else {}))

            if plotter.legend:
                ax_mag.legend(fontsize=plotter.legend_fontsize or None)
                ax_phase.legend(fontsize=plotter.legend_fontsize or None)

            plt.tight_layout()
            self._gui_save(plotter, fig=fig)  # save BEFORE show
            plt.show()


